```csharp
using System;
using System.Threading;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        using var cts = new CancellationTokenSource();

        _ = Task.Run(() =>
        {
            if (Console.ReadKey(true).Key == ConsoleKey.C)
            {
                Console.WriteLine("\nAnnulation demandée...");
                cts.Cancel();
            }
        });

        try
        {
            await SimulerTelechargement(cts.Token);
            Console.WriteLine("Téléchargement terminé");
        }
        catch (OperationCanceledException)
        {
            Console.WriteLine("Téléchargement annulé");
        }
    }

    static async Task SimulerTelechargement(CancellationToken token)
    {
        Console.WriteLine("Téléchargement en cours... Appuyez sur C pour annuler");
        await Task.Delay(5000, token);
    }
}
```

